import{_ as t,o as a,c as o,a4 as d}from"./chunks/framework.4M7SpZrd.js";const f=JSON.parse('{"title":"DeepGuard — Deepfake Detection v3","description":"","frontmatter":{},"headers":[],"relativePath":"motores/motor-21-deepfake.md","filePath":"motores/motor-21-deepfake.md"}'),s={name:"motores/motor-21-deepfake.md"};function i(n,e,r,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="deepguard-—-deepfake-detection-v3" tabindex="-1">DeepGuard — Deepfake Detection v3 <a class="header-anchor" href="#deepguard-—-deepfake-detection-v3" aria-label="Permalink to &quot;DeepGuard — Deepfake Detection v3&quot;">​</a></h1><p><strong>Status:</strong> Ativo <strong>Queue:</strong> <code>celery_face</code> (face-worker) <strong>Dependencias:</strong> scipy, Pillow, numpy, InsightFace (face-crop), onnxruntime (modelos ONNX) <strong>Mock mode:</strong> Retorna <code>is_fake=False</code> quando scipy nao esta instalado <strong>Gating:</strong> Pro/Premium/Founder</p><h2 id="metadados" tabindex="-1">Metadados <a class="header-anchor" href="#metadados" aria-label="Permalink to &quot;Metadados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td><strong>Motor ID</strong></td><td>21</td></tr><tr><td><strong>Nome</strong></td><td>DeepGuard</td></tr><tr><td><strong>Slug</strong></td><td>deepguard</td></tr><tr><td><strong>Categoria</strong></td><td>Analysis</td></tr><tr><td><strong>Status</strong></td><td>ATIVO</td></tr><tr><td><strong>Frequencia</strong></td><td>Sob Demanda</td></tr><tr><td><strong>Fila Celery</strong></td><td>celery</td></tr><tr><td><strong>Dependencias Externas</strong></td><td>DeepFaceLab, MediaPipe</td></tr><tr><td><strong>Chaves de Config</strong></td><td>—</td></tr></tbody></table><h2 id="arquitetura" tabindex="-1">Arquitetura <a class="header-anchor" href="#arquitetura" aria-label="Permalink to &quot;Arquitetura&quot;">​</a></h2><p>Pipeline multi-camada com face-crop + modelos treinados:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Imagem → Face-Crop (InsightFace) → [6 camadas] → Score Final</span></span>
<span class="line"><span>                                     ├── DCT (espectral)</span></span>
<span class="line"><span>                                     ├── ELA (compressao)</span></span>
<span class="line"><span>                                     ├── Noise (ruido GAN)</span></span>
<span class="line"><span>                                     ├── Patches (coerencia local)</span></span>
<span class="line"><span>                                     ├── Boundary (zona de transicao face/fundo)</span></span>
<span class="line"><span>                                     ├── ONNX Model 1 (EfficientNet-B4 DeepfakeBench)</span></span>
<span class="line"><span>                                     └── ONNX Model 2 (EfficientNet-B7 DFDC winner)</span></span></code></pre></div><h2 id="camadas-de-analise" tabindex="-1">Camadas de Analise <a class="header-anchor" href="#camadas-de-analise" aria-label="Permalink to &quot;Camadas de Analise&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Camada</th><th>Tipo</th><th>O que detecta</th><th>Peso (dual ONNX)</th><th>Peso (1 ONNX)</th><th>Peso (sem ONNX)</th></tr></thead><tbody><tr><td>DCT</td><td>Heuristica CPU</td><td>Artefatos espectrais, simetria, queda de frequencia</td><td>5%</td><td>8%</td><td>25%</td></tr><tr><td>ELA</td><td>Heuristica CPU</td><td>Areas re-comprimidas, colagem face/fundo</td><td>5%</td><td>8%</td><td>20%</td></tr><tr><td>Noise</td><td>Heuristica CPU</td><td>Fingerprint GAN, correlacao entre canais</td><td>5%</td><td>8%</td><td>20%</td></tr><tr><td>Patches</td><td>Heuristica CPU</td><td>Inconsistencia textura centro vs borda</td><td>3%</td><td>6%</td><td>15%</td></tr><tr><td>Boundary</td><td>Heuristica CPU</td><td>Blending na zona de transicao facial (face swaps)</td><td>7%</td><td>10%</td><td>20%</td></tr><tr><td>ONNX B4</td><td>Modelo treinado</td><td>Classificacao real/fake (EfficientNet-B4, FF++)</td><td>35%</td><td>60%</td><td>—</td></tr><tr><td>ONNX B7</td><td>Modelo treinado</td><td>Classificacao real/fake (EfficientNet-B7, DFDC)</td><td>40%</td><td>—</td><td>—</td></tr></tbody></table><h3 id="boundary-analysis-v3" tabindex="-1">Boundary Analysis (v3) <a class="header-anchor" href="#boundary-analysis-v3" aria-label="Permalink to &quot;Boundary Analysis (v3)&quot;">​</a></h3><p>Nova camada inspirada em SBI (Self-Blended Images, CVPR 2022) e Face X-Ray (CVPR 2020). Analisa a zona de transicao ao redor da borda facial detectada por InsightFace:</p><ol><li><strong>Gradiente de borda:</strong> Descontinuidade de gradiente na fronteira face/fundo</li><li><strong>Inconsistencia de ruido:</strong> Diferenca estatistica de ruido entre interior e exterior da face</li><li><strong>Suavizacao artificial:</strong> Detecta gaussian blur/feather usado no blending de face swaps</li></ol><p>Requer face_info (bbox + orig_array) do <code>crop_face_with_info()</code>. Se nenhum rosto detectado, score = 0.</p><h2 id="face-crop" tabindex="-1">Face-Crop <a class="header-anchor" href="#face-crop" aria-label="Permalink to &quot;Face-Crop&quot;">​</a></h2><p>Antes de analisar, o motor cropa a face usando InsightFace AntelopeV2 (mesmo modelo do FaceID). Reusa o face-worker existente (Dockerfile.face).</p><ul><li>Se nenhum rosto detectado: analisa imagem completa</li><li>Se multiplos rostos: usa o maior</li><li>Margem de 20% ao redor do rosto</li><li><code>crop_face_with_info()</code> retorna crop + bbox/landmarks para boundary analysis</li></ul><p><strong>Codigo:</strong> <code>app/engines/face_crop.py</code></p><h2 id="modelos-onnx" tabindex="-1">Modelos ONNX <a class="header-anchor" href="#modelos-onnx" aria-label="Permalink to &quot;Modelos ONNX&quot;">​</a></h2><h3 id="modelo-1-efficientnet-b4-deepfakebench" tabindex="-1">Modelo 1: EfficientNet-B4 (DeepfakeBench) <a class="header-anchor" href="#modelo-1-efficientnet-b4-deepfakebench" aria-label="Permalink to &quot;Modelo 1: EfficientNet-B4 (DeepfakeBench)&quot;">​</a></h3><ul><li><strong>Fonte:</strong> DeepfakeBench (<code>effnb4_best.pth</code>, 67.7 MB)</li><li><strong>Arquitetura:</strong> EfficientNet-B4 treinado no FaceForensics++ (c23)</li><li><strong>AUC:</strong> 93.89% within-domain, 77.18% cross-domain</li><li><strong>Input:</strong> 256x256, normalizado com mean=[0.5,0.5,0.5], std=[0.5,0.5,0.5]</li><li><strong>Output:</strong> 2 classes [real, fake] → softmax → prob_fake</li><li><strong>Licenca:</strong> CC BY-NC 4.0</li><li><strong>Localizacao:</strong> <code>models/deepfake_efficientnet.onnx</code></li></ul><h3 id="modelo-2-efficientnet-b7-dfdc-winner-—-v3" tabindex="-1">Modelo 2: EfficientNet-B7 (DFDC Winner) — v3 <a class="header-anchor" href="#modelo-2-efficientnet-b7-dfdc-winner-—-v3" aria-label="Permalink to &quot;Modelo 2: EfficientNet-B7 (DFDC Winner) — v3&quot;">​</a></h3><ul><li><strong>Fonte:</strong> selimsef/dfdc_deepfake_challenge (Kaggle DFDC Champion, 859 stars)</li><li><strong>Arquitetura:</strong> EfficientNet-B7 (timm <code>tf_efficientnet_b7_ns</code>) com head Linear(2560, 1)</li><li><strong>Dataset:</strong> DFDC (8 metodos de face swap, 960 sujeitos — mais diverso que FF++)</li><li><strong>Input:</strong> 380x380, normalizado com ImageNet mean/std</li><li><strong>Output:</strong> 1 logit → sigmoid → prob_fake</li><li><strong>Licenca:</strong> MIT</li><li><strong>Localizacao:</strong> <code>models/dfdc_efficientnet_b7.onnx</code></li></ul><p><strong>Conversao dos modelos:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Modelo 1 (DeepfakeBench)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> torch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> torchvision</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> efficientnet_pytorch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/download_deepfake_model.py</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Modelo 2 (DFDC)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> torch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> timm==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.4.12</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/download_dfdc_model.py</span></span></code></pre></div><p><strong>Codigo:</strong> <code>app/engines/deepfake_model.py</code> (classes <code>DeepfakeONNX</code> e <code>DFDCModelONNX</code>)</p><h2 id="boosts-de-confianca" tabindex="-1">Boosts de Confianca <a class="header-anchor" href="#boosts-de-confianca" aria-label="Permalink to &quot;Boosts de Confianca&quot;">​</a></h2><p>Alem da media ponderada, o ensemble aplica boosts em casos especificos:</p><table tabindex="0"><thead><tr><th>Condicao</th><th>Boost</th><th>Razao</th></tr></thead><tbody><tr><td>Ambos ONNX concordam (score &gt; 0.5)</td><td>+min(score)*10%</td><td>Concordancia forte de 2 modelos independentes</td></tr><tr><td>Boundary score &gt; 0.5</td><td>+boundary*12%</td><td>Forte sinal de face swap</td></tr><tr><td>3+ heuristicas &gt;= 0.3 (sem ONNX)</td><td>*1.3x</td><td>Multiplas evidencias convergem</td></tr></tbody></table><h2 id="compensacao-jpeg" tabindex="-1">Compensacao JPEG <a class="header-anchor" href="#compensacao-jpeg" aria-label="Permalink to &quot;Compensacao JPEG&quot;">​</a></h2><p>Imagens muito comprimidas (quality &lt; 75) produzem artefatos que mimetizam sinais de deepfake nas heuristicas. O motor aplica penalizacao proporcional a qualidade JPEG estimada nos scores de DCT, ELA e Noise.</p><p>Os modelos ONNX NAO sao afetados pela penalizacao (ja sao robustos a compressao).</p><h2 id="classificacao" tabindex="-1">Classificacao <a class="header-anchor" href="#classificacao" aria-label="Permalink to &quot;Classificacao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Label</th><th>Condicao</th></tr></thead><tbody><tr><td>AUTENTICO</td><td>score &lt; threshold (default 0.4)</td></tr><tr><td>SUSPEITO</td><td>score &gt;= threshold AND confidence &lt;= 0.75</td></tr><tr><td>DEEPFAKE</td><td>score &gt;= threshold AND confidence &gt; 0.75</td></tr></tbody></table><h2 id="configuracao-env" tabindex="-1">Configuracao (.env) <a class="header-anchor" href="#configuracao-env" aria-label="Permalink to &quot;Configuracao (.env)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variavel</th><th>Default</th><th>Descricao</th></tr></thead><tbody><tr><td><code>DEEPFAKE_ENABLED</code></td><td><code>true</code></td><td>Habilitar DeepGuard</td></tr><tr><td><code>DEEPFAKE_DCT_THRESHOLD</code></td><td><code>0.4</code></td><td>Limiar para classificar como fake</td></tr><tr><td><code>DEEPFAKE_MAX_IMAGE_SIZE</code></td><td><code>10000000</code></td><td>Tamanho maximo (10MB)</td></tr><tr><td><code>DEEPFAKE_QUEUE</code></td><td><code>celery_face</code></td><td>Queue Celery (face-worker)</td></tr><tr><td><code>DEEPFAKE_FACE_CROP_ENABLED</code></td><td><code>true</code></td><td>Cropar face antes de analisar</td></tr><tr><td><code>DEEPFAKE_ONNX_MODEL_PATH</code></td><td><code>models/deepfake_efficientnet.onnx</code></td><td>Caminho do modelo B4</td></tr></tbody></table><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rota</th><th>Metodo</th><th>Acesso</th><th>Descricao</th></tr></thead><tbody><tr><td><code>/api/v1/analysis/deepfake</code></td><td>POST</td><td>Pro/Premium</td><td>Analise de deepfake (usuario)</td></tr><tr><td><code>/api/v1/admin/deepfake/analyze</code></td><td>POST</td><td>Admin</td><td>Analise com detalhes tecnicos</td></tr><tr><td><code>/api/v1/admin/deepfake/stats</code></td><td>GET</td><td>Admin</td><td>Status e configuracao</td></tr></tbody></table><h2 id="fluxo-de-execucao" tabindex="-1">Fluxo de Execucao <a class="header-anchor" href="#fluxo-de-execucao" aria-label="Permalink to &quot;Fluxo de Execucao&quot;">​</a></h2><ol><li>API recebe imagem → valida tipo/tamanho</li><li>Envia para <code>celery_face</code> queue (task <code>deepfake.analyze</code>)</li><li>Face-worker recebe → face-crop com InsightFace (retorna crop + face_info)</li><li>Roda 4 heuristicas CPU (DCT, ELA, Noise, Patches)</li><li>Roda boundary analysis (se face detectada, usa bbox da face_info)</li><li>Roda modelos ONNX (EfficientNet-B4 + B7, se disponíveis)</li><li>Calcula score ensemble ponderado → retorna resultado</li><li>Fallback: se Celery falha, roda localmente sem face-crop/ONNX</li></ol><h2 id="reaproveitamento-de-motores" tabindex="-1">Reaproveitamento de Motores <a class="header-anchor" href="#reaproveitamento-de-motores" aria-label="Permalink to &quot;Reaproveitamento de Motores&quot;">​</a></h2><ul><li><strong>FaceID (Face Recognition):</strong> InsightFace para face-crop + bbox/landmarks</li><li><strong>ShieldAI (NCII):</strong> face-worker container (onnxruntime, InsightFace ja instalados)</li><li><strong>Queue celery_face:</strong> worker dedicado ja configurado</li></ul><h2 id="arquivos" tabindex="-1">Arquivos <a class="header-anchor" href="#arquivos" aria-label="Permalink to &quot;Arquivos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caminho</th><th>Responsabilidade</th></tr></thead><tbody><tr><td><code>app/engines/deepfake_detector.py</code></td><td>Pipeline principal (6 camadas + scoring)</td></tr><tr><td><code>app/engines/face_crop.py</code></td><td>Face-crop utility + <code>crop_face_with_info()</code></td></tr><tr><td><code>app/engines/deepfake_model.py</code></td><td>Wrappers ONNX (DeepfakeONNX + DFDCModelONNX)</td></tr><tr><td><code>app/api/v1/analysis.py</code></td><td>Endpoint usuario</td></tr><tr><td><code>app/api/v1/admin/deepfake_admin.py</code></td><td>Endpoint admin</td></tr><tr><td><code>app/tasks/embedding_tasks.py</code></td><td>Task Celery (deepfake.analyze)</td></tr><tr><td><code>scripts/download_deepfake_model.py</code></td><td>Download + conversao modelo B4</td></tr><tr><td><code>scripts/download_dfdc_model.py</code></td><td>Download + conversao modelo B7 (DFDC)</td></tr><tr><td><code>frontend-admin/app/(admin)/deepfake/page.tsx</code></td><td>UI admin</td></tr><tr><td><code>tests/test_deepfake_detector.py</code></td><td>Testes do detector</td></tr><tr><td><code>tests/test_face_crop.py</code></td><td>Testes do face-crop</td></tr><tr><td><code>tests/test_deepfake_model.py</code></td><td>Testes do wrapper ONNX</td></tr></tbody></table><h2 id="seguranca-e-lgpd" tabindex="-1">Seguranca e LGPD <a class="header-anchor" href="#seguranca-e-lgpd" aria-label="Permalink to &quot;Seguranca e LGPD&quot;">​</a></h2><ul><li><strong>LGPD:</strong> <code>del img_bytes</code> + <code>del img_bytes_b64</code> imediatamente apos processamento em tasks e endpoints</li><li><strong>Memory:</strong> <code>face_info[&quot;orig_array&quot;]</code> removido com <code>.pop()</code> apos boundary analysis</li><li><strong>Memory:</strong> todas as imagens PIL fechadas com <code>.close()</code> apos uso (previne leak de handles)</li><li><strong>Memory:</strong> <code>del img_bgr</code> apos deteccao de face (libera copia BGR)</li><li><strong>Path traversal:</strong> modelos ONNX validados para estar dentro de <code>models/</code> antes de carregar</li><li><strong>Race condition:</strong> flags <code>_checked</code> setadas APOS try/except (retry em caso de erro transiente)</li><li><strong>Download:</strong> verificacao de tamanho do checkpoint, <code>weights_only=True</code> tentado antes de <code>False</code></li><li><strong>Fallback:</strong> se Celery falha, analise local sem face-crop/ONNX (graceful degradation)</li></ul><h2 id="referencias" tabindex="-1">Referencias <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referencias&quot;">​</a></h2><ul><li>Frank et al. (2020) &quot;Leveraging Frequency Analysis for Deep Fake Image Recognition&quot;</li><li>DeepfakeBench (github.com/SCLBD/DeepfakeBench) — EfficientNet-B4 pre-treinado</li><li>selimsef/dfdc_deepfake_challenge (MIT) — EfficientNet-B7 DFDC winner</li><li>&quot;Detecting Deepfakes with Self-Blended Images&quot; (CVPR 2022) — boundary analysis</li><li>&quot;CNN-generated images are surprisingly easy to spot&quot; (CVPR 2020)</li><li>&quot;Face X-Ray for More General Face Forgery Detection&quot; (CVPR 2020)</li></ul><h2 id="testes" tabindex="-1">Testes <a class="header-anchor" href="#testes" aria-label="Permalink to &quot;Testes&quot;">​</a></h2><ul><li><strong>Unit tests:</strong> <code>tests/test_deepfake_detector.py</code>, <code>tests/test_face_crop.py</code>, <code>tests/test_deepfake_model.py</code></li><li><strong>Cobertura:</strong> 70%</li><li><strong>Gaps conhecidos:</strong> Testes com modelos ONNX reais (CI usa heuristicas)</li></ul><h2 id="relacionamentos" tabindex="-1">Relacionamentos <a class="header-anchor" href="#relacionamentos" aria-label="Permalink to &quot;Relacionamentos&quot;">​</a></h2><ul><li><strong>Depende de:</strong> Motor 6 (FaceID — InsightFace face-crop), scipy, onnxruntime, celery_face queue</li><li><strong>Consumido por:</strong> Frontend (analise de deepfake Pro/Premium), Admin (analise com detalhes tecnicos)</li><li><strong>Conflita com:</strong> Nenhum</li></ul>`,51)])])}const u=t(s,[["render",i]]);export{f as __pageData,u as default};
